CREATE   PROCEDURE [assoc].[sp_Assets_BulkCreate] @Assets [assoc].[AssetTableType] READONLY AS BEGIN SET NOCOUNT ON; INSERT INTO [assoc].[Assets] ([ParentId], [TenantId], [AssociationId], [Name], [Description], [AssetType], [MetadataJson], [CreatedDate], [CreatedBy], [IsActive]) SELECT [ParentId], [TenantId], [AssociationId], [Name], [Description], [AssetType], [MetadataJson], [CreatedDate], [CreatedBy], [IsActive] FROM @Assets; SELECT @@ROWCOUNT; END